@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

@app.route("/users/active", methods=["POST"])
def set_active_users():
    data = request.get_json(silent=True) or {}
    value = int(data.get("count", 0))
    ACTIVE_USERS.set(value)
    return jsonify({"active_users": value})

@app.route("/queue/<queue_name>", methods=["POST"])
def set_queue_depth(queue_name):
    data = request.get_json(silent=True) or {}
    depth = int(data.get("depth", 0))
    QUEUE_DEPTH.labels(queue_name=queue_name).set(depth)
    return jsonify({"queue_name": queue_name, "depth": depth})

@app.route("/order", methods=["POST"])
def create_order():
    data = request.get_json(silent=True) or {}
    amount = float(data.get("amount", round(random.uniform(10, 500), 2)))
    success = bool(data.get("success", True))
    ORDER_VALUE.observe(amount)
    BUSINESS_EVENTS_TOTAL.labels(
        event_type="order_created",
        status="success" if success else "failed",
    ).inc()
    return jsonify({"amount": amount, "success": success})

@app.route("/event/<event_type>", methods=["POST"])
def process_event(event_type):
    data = request.get_json(silent=True) or {}
    status = data.get("status", "success")
    BUSINESS_EVENTS_TOTAL.labels(event_type=event_type, status=status).inc()
    return jsonify({"event_type": event_type, "status": status})

@app.route("/metrics", methods=["GET"])
def metrics():
    if PROMETHEUS_MULTIPROC_DIR:
        registry = CollectorRegistry()
        multiprocess.MultiProcessCollector(registry)
        output = generate_latest(registry)
    else:
        output = generate_latest()
    return app.response_class(output, mimetype=CONTENT_TYPE_LATEST)

